{
  "name": "sikret-server",
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "start": "node src/index.js",
    "dev": "node --watch src/index.js"
  },
  "dependencies": {
    "cors": "^2.8.5",
    "express": "^4.21.2",
    "uuid": "^11.1.0"
  }
}

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const DATA_FILE = path.join(__dirname, '..', 'data.json');

const defaultData = () => ({
  users: {},
  queue: [],
  swaps: {},
});

export function loadStore() {
  try {
    if (fs.existsSync(DATA_FILE)) {
      return JSON.parse(fs.readFileSync(DATA_FILE, 'utf8'));
    }
  } catch {
    /* fresh */
  }
  return defaultData();
}

export function saveStore(data) {
  fs.mkdirSync(path.dirname(DATA_FILE), { recursive: true });
  fs.writeFileSync(DATA_FILE, JSON.stringify(data, null, 2));
}

export function todayKey() {
  return new Date().toISOString().slice(0, 10);
}

const BOT_RESPONSES = [
  'לפעמים אני מרגיש שאני מחזיק הכל לבד, ואף אחד לא יודע כמה זה כבד. כתבתי את זה כאן כי לא יכולתי לומר את זה בקול.',
  'יש סוד קטן שאני אוהב: אני עדיין שומר הודעה מישהו שלא אמור לדעת שזה מרגש אותי. זה מטופל, אבל הלב לא תמיד מסתדר.',
  'הייתי רוצה להגיד למישהו אנונימי: תודה על ההקשבה. גם בלי שם, זה מרגיש שמישהו שם.',
  'אני מתוודה שאני מפחד מהדחייה יותר ממה שאני מוכן להודות בו. זו המעטפה שלי להיום.',
];

export function pickBotResponse() {
  return BOT_RESPONSES[Math.floor(Math.random() * BOT_RESPONSES.length)];
}

export function tryMatch(data) {
  const waiting = data.queue.filter((q) => !q.matched);
  for (let i = 0; i < waiting.length; i++) {
    for (let j = i + 1; j < waiting.length; j++) {
      const a = waiting[i];
      const b = waiting[j];
      if (a.intention === b.intention && a.userId !== b.userId) {
        return createSwap(data, a, b);
      }
    }
  }
  return null;
}

function createSwap(data, entryA, entryB) {
  const swapId = `swap_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
  const swap = {
    id: swapId,
    intention: entryA.intention,
    openMode: entryA.openMode,
    status: 'waiting_lock',
    createdAt: Date.now(),
    userA: entryA.userId,
    userB: entryB.userId,
    lockA: false,
    lockB: false,
    contentA: entryA.content,
    contentB: entryB.content,
    isBot: false,
  };
  data.swaps[swapId] = swap;
  data.queue = data.queue.filter((q) => q.id !== entryA.id && q.id !== entryB.id);
  entryA.matched = swapId;
  entryB.matched = swapId;
  return swap;
}

export function createBotSwap(data, entry) {
  const swapId = `swap_bot_${Date.now()}`;
  const swap = {
    id: swapId,
    intention: entry.intention,
    openMode: entry.openMode,
    status: 'waiting_lock',
    createdAt: Date.now(),
    userA: entry.userId,
    userB: 'bot',
    lockA: false,
    lockB: true,
    contentA: entry.content,
    contentB: pickBotResponse(),
    isBot: true,
  };
  data.swaps[swapId] = swap;
  data.queue = data.queue.filter((q) => q.id !== entry.id);
  return swap;
}

import cors from 'cors';
import express from 'express';
import { v4 as uuidv4 } from 'uuid';
import { createBotSwap, tryMatch } from './match.js';
import { loadStore, saveStore, todayKey } from './store.js';

const app = express();
const PORT = process.env.PORT || 3847;

app.use(cors());
app.use(express.json({ limit: '32kb' }));

function getOrCreateUser(data, userId) {
  if (!userId || !data.users[userId]) {
    const id = uuidv4();
    data.users[id] = {
      id,
      trustScore: 50,
      suspendedUntil: null,
      completedSwaps: 0,
      firstCompletedAt: null,
      daily: {},
      reportsReceived: 0,
      createdAt: Date.now(),
    };
    return data.users[id];
  }
  return data.users[userId];
}

function dailyLimit(user) {
  const day = user.daily[todayKey()] || { completed: 0 };
  if (!user.firstCompletedAt) return 2;
  return 3;
}

function canStartSwap(user) {
  if (user.suspendedUntil && user.suspendedUntil > Date.now()) {
    return { ok: false, reason: 'suspended', until: user.suspendedUntil };
  }
  const day = user.daily[todayKey()] || { completed: 0 };
  const limit = dailyLimit(user);
  if (day.completed >= limit) {
    return { ok: false, reason: 'quota', limit, used: day.completed };
  }
  return { ok: true, limit, used: day.completed };
}

function activeSwapForUser(data, userId) {
  return Object.values(data.swaps).find(
    (s) =>
      (s.userA === userId || s.userB === userId) &&
      !['completed', 'abandoned'].includes(s.status),
  );
}

function swapViewForUser(swap, userId) {
  const isA = swap.userA === userId;
  const myLocked = isA ? swap.lockA : swap.lockB;
  const peerLocked = isA ? swap.lockB : swap.lockA;
  const bothLocked = swap.lockA && swap.lockB;
  const openMode = swap.openMode;

  let phase = 'waiting_lock';
  if (bothLocked) phase = 'opened';
  else if (myLocked && !peerLocked) phase = 'waiting_peer';
  else if (!myLocked && peerLocked && openMode === 'when_peer') phase = 'peer_ready';

  const canSeePeer =
    bothLocked &&
    (openMode === 'together' || (openMode === 'when_peer' && peerLocked));

  return {
    id: swap.id,
    intention: swap.intention,
    openMode: swap.openMode,
    status: swap.status,
    phase,
    myLocked,
    peerLocked,
    bothLocked,
    isBot: swap.isBot,
    peerContent: canSeePeer ? (isA ? swap.contentB : swap.contentA) : null,
    peerAlias: swap.isBot ? 'מעטפה-ערפילית' : isA ? 'מעטפה-כחולה' : 'מעטפה-ורודה',
  };
}

app.get('/health', (_, res) => res.json({ ok: true }));

app.post('/api/users', (req, res) => {
  const data = loadStore();
  const existing = req.body.userId;
  const user = getOrCreateUser(data, existing);
  saveStore(data);
  res.json({ userId: user.id });
});

app.get('/api/me', (req, res) => {
  const data = loadStore();
  const userId = req.headers['x-user-id'];
  if (!userId || !data.users[userId]) {
    return res.status(401).json({ error: 'unknown_user' });
  }
  const user = data.users[userId];
  const day = user.daily[todayKey()] || { completed: 0 };
  const quota = canStartSwap(user);
  const active = activeSwapForUser(data, userId);
  saveStore(data);
  res.json({
    userId: user.id,
    trustScore: user.trustScore,
    suspendedUntil: user.suspendedUntil,
    dailyCompleted: day.completed,
    dailyLimit: dailyLimit(user),
    canStart: quota.ok,
    quotaReason: quota.reason || null,
    activeSwapId: active?.id || null,
  });
});

app.post('/api/queue/join', (req, res) => {
  const data = loadStore();
  const userId = req.headers['x-user-id'];
  const user = getOrCreateUser(data, userId);
  const { intention, openMode, content } = req.body;

  if (!intention || !openMode || !content) {
    return res.status(400).json({ error: 'missing_fields' });
  }
  if (content.length < 100 || content.length > 1500) {
    return res.status(400).json({ error: 'invalid_length', min: 100, max: 1500 });
  }

  const quota = canStartSwap(user);
  if (!quota.ok) return res.status(403).json({ error: quota.reason, ...quota });

  if (activeSwapForUser(data, userId)) {
    return res.status(409).json({ error: 'active_swap' });
  }

  data.queue = data.queue.filter((q) => q.userId === userId && !q.matched);

  const entry = {
    id: uuidv4(),
    userId: user.id,
    intention,
    openMode,
    content: content.trim(),
    joinedAt: Date.now(),
    matched: null,
  };
  data.queue.push(entry);

  let swap = tryMatch(data);
  if (!swap) {
    saveStore(data);
    res.json({ status: 'queued', queueId: entry.id });
    setTimeout(() => {
      const d = loadStore();
      const still = d.queue.find((q) => q.id === entry.id && !q.matched);
      if (still) {
        createBotSwap(d, still);
        saveStore(d);
      }
    }, 12000);
    return;
  }

  saveStore(data);
  res.json({ status: 'matched', swapId: swap.id });
});

app.get('/api/queue/status', (req, res) => {
  const data = loadStore();
  const userId = req.headers['x-user-id'];
  const entry = data.queue.find((q) => q.userId === userId && !q.matched);
  const active = activeSwapForUser(data, userId);
  if (active) {
    return res.json({ status: 'matched', swapId: active.id });
  }
  if (entry) return res.json({ status: 'queued', queueId: entry.id });
  res.json({ status: 'idle' });
});

app.delete('/api/queue/leave', (req, res) => {
  const data = loadStore();
  const userId = req.headers['x-user-id'];
  data.queue = data.queue.filter((q) => !(q.userId === userId && !q.matched));
  saveStore(data);
  res.json({ ok: true });
});

app.get('/api/swaps/:id', (req, res) => {
  const data = loadStore();
  const userId = req.headers['x-user-id'];
  const swap = data.swaps[req.params.id];
  if (!swap) return res.status(404).json({ error: 'not_found' });
  if (swap.userA !== userId && swap.userB !== userId) {
    return res.status(403).json({ error: 'forbidden' });
  }
  res.json(swapViewForUser(swap, userId));
});

app.post('/api/swaps/:id/lock', (req, res) => {
  const data = loadStore();
  const userId = req.headers['x-user-id'];
  const swap = data.swaps[req.params.id];
  if (!swap) return res.status(404).json({ error: 'not_found' });
  const isA = swap.userA === userId;
  if (!isA && swap.userB !== userId) return res.status(403).json({ error: 'forbidden' });

  if (isA) swap.lockA = true;
  else swap.lockB = true;

  if (swap.lockA && swap.lockB) {
    swap.status = 'opened';
    if (swap.isBot) swap.status = 'opened';
  }

  saveStore(data);
  res.json(swapViewForUser(swap, userId));
});

app.post('/api/swaps/:id/feedback', (req, res) => {
  const data = loadStore();
  const userId = req.headers['x-user-id'];
  const { type } = req.body;
  const swap = data.swaps[req.params.id];
  if (!swap) return res.status(404).json({ error: 'not_found' });

  const peerId = swap.userA === userId ? swap.userB : swap.userA;
  const user = data.users[userId];
  const peer = peerId !== 'bot' ? data.users[peerId] : null;

  if (type === 'touched' && peer) peer.trustScore = Math.min(100, peer.trustScore + 8);
  if (type === 'dishonest' && peer) {
    peer.trustScore = Math.max(0, peer.trustScore - 15);
    peer.reportsReceived += 1;
    if (peer.reportsReceived >= 3) {
      peer.suspendedUntil = Date.now() + 24 * 60 * 60 * 1000;
    }
  }
  if (type === 'report' && peer) {
    peer.trustScore = Math.max(0, peer.trustScore - 25);
    peer.suspendedUntil = Date.now() + 7 * 24 * 60 * 60 * 1000;
  }

  if (!user.daily[todayKey()]) user.daily[todayKey()] = { completed: 0 };
  user.daily[todayKey()].completed += 1;
  if (!user.firstCompletedAt) user.firstCompletedAt = Date.now();
  user.completedSwaps += 1;
  swap.status = 'completed';

  saveStore(data);
  res.json({ ok: true, dailyCompleted: user.daily[todayKey()].completed });
});

app.post('/api/swaps/:id/complete', (req, res) => {
  const data = loadStore();
  const userId = req.headers['x-user-id'];
  const swap = data.swaps[req.params.id];
  if (!swap) return res.status(404).json({ error: 'not_found' });

  const user = data.users[userId];
  if (!user.daily[todayKey()]) user.daily[todayKey()] = { completed: 0 };
  if (swap.status !== 'completed') {
    user.daily[todayKey()].completed += 1;
    if (!user.firstCompletedAt) user.firstCompletedAt = Date.now();
    swap.status = 'completed';
  }
  saveStore(data);
  res.json({ ok: true });
});

app.listen(PORT, '0.0.0.0', () => {
  console.log(`Sikret API http://0.0.0.0:${PORT}`);
});

