import Constants from 'expo-constants';
import { Platform } from 'react-native';

const host =
  Constants.expoConfig?.extra?.apiUrl ??
  (Platform.OS === 'android' ? 'http://10.0.2.2:3847' : 'http://127.0.0.1:3847');

async function request<T>(
  path: string,
  options: RequestInit & { userId?: string | null } = {},
): Promise<T> {
  const { userId, ...init } = options;
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    ...(init.headers as Record<string, string>),
  };
  if (userId) headers['x-user-id'] = userId;

  const res = await fetch(`${host}${path}`, { ...init, headers });
  const body = await res.json().catch(() => ({}));
  if (!res.ok) {
    const err = new Error(body.error || 'request_failed') as Error & { code?: string; data?: unknown };
    err.code = body.error;
    (err as Error & { data: unknown }).data = body;
    throw err;
  }
  return body as T;
}

export type MeResponse = {
  userId: string;
  trustScore: number;
  suspendedUntil: number | null;
  dailyCompleted: number;
  dailyLimit: number;
  canStart: boolean;
  quotaReason: string | null;
