import { LinearGradient } from 'expo-linear-gradient';
import { useEffect, useRef } from 'react';
import { Animated, Easing, StyleSheet, View } from 'react-native';
import { colors } from '../theme';

type Mode = 'idle' | 'queue' | 'locked' | 'open';

type Props = { mode?: Mode; size?: number };

export function EnvelopeOrb({ mode = 'idle', size = 140 }: Props) {
  const spin = useRef(new Animated.Value(0)).current;
  const pulse = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    if (mode === 'queue') {
      Animated.loop(
        Animated.timing(spin, {
          toValue: 1,
          duration: 4000,
          easing: Easing.linear,
          useNativeDriver: true,
        }),
      ).start();
    } else {
      spin.stopAnimation();
      spin.setValue(0);
    }
  }, [mode, spin]);

  useEffect(() => {
    if (mode === 'open') {
      Animated.sequence([
        Animated.timing(pulse, { toValue: 1, duration: 400, useNativeDriver: true }),
        Animated.timing(pulse, { toValue: 0, duration: 600, useNativeDriver: true }),
      ]).start();
    }
  }, [mode, pulse]);

  const rotate = spin.interpolate({
    inputRange: [0, 1],
    outputRange: ['0deg', '360deg'],
  });

  const scale = pulse.interpolate({
    inputRange: [0, 1],
    outputRange: [1, 1.15],
  });

  const ringColors =
    mode === 'locked'
      ? [colors.locked, colors.neonMagenta, colors.locked]
      : [colors.neonCyan, colors.neonPurple, colors.neonMagenta, colors.neonCyan];

