export default function QueueScreen() {
  const { userId, draft, refreshMe } = useApp();
  const [status, setStatus] = useState<'joining' | 'queued' | 'error'>('joining');
  const joined = useRef(false);

  useEffect(() => {
    if (!userId || joined.current) return;
    joined.current = true;

    (async () => {
      try {
        const res = await api.joinQueue(userId, {
          intention: draft.intention!,
          openMode: draft.openMode!,
          content: draft.content!,
        });
        if (res.status === 'matched' && res.swapId) {
          router.replace({ pathname: '/lock', params: { id: res.swapId } });
          return;
        }
        setStatus('queued');
      } catch (e: unknown) {
        const err = e as Error & { code?: string };
        setStatus('error');
        Alert.alert('שגיאה', err.code === 'quota' ? 'הגעת למכסה היומית' : 'לא הצלחנו להיכנס לתור');
        router.back();
      }
    })();
  }, [userId, draft]);

  useEffect(() => {
    if (status !== 'queued' || !userId) return;
    const t = setInterval(async () => {
      const s = await api.queueStatus(userId);
      if (s.status === 'matched' && s.swapId) {
        clearInterval(t);
        await refreshMe();
        router.replace({ pathname: '/lock', params: { id: s.swapId } });
      }
    }, 2000);
    return () => clearInterval(t);
  }, [status, userId, refreshMe]);

  const leave = async () => {
    if (userId) await api.leaveQueue(userId);
    router.back();
  };

  return (
    <Screen>
      <Title>מחפשים מעטפה...</Title>
      <Subtitle>מותאם לפי הכוונה שלך. אם אין זר — מעטפת אנונימית תצטרף תוך כ־12 שניות (בטא).</Subtitle>
      <EnvelopeOrb mode="queue" />
      <Text style={styles.hint}>{status === 'joining' ? 'נכנס לתור...' : 'ממתין לזר...'}</Text>
      <OutlineButton label="יציאה מהתור" onPress={leave} />
    </Screen>
  );
}

