    setLocking(true);
    try {
      const view = await api.lockSwap(userId, id);
      router.replace({ pathname: '/swap', params: { id: view.id } });
    } catch {
      Alert.alert('שגיאה', 'לא הצלחנו לנעול');
    } finally {
      setLocking(false);
    }
  };

  return (
    <Screen scroll>
      <View style={styles.center}>
        <EnvelopeOrb mode="locked" />
      </View>
      <Title>נעילה סופית</Title>
      <Subtitle>מה שננעל לא ניתן לערוך, למחוק או לבטל.</Subtitle>
      <GlassCard>
        <Text style={styles.warn}>
          ודא/י שהטקסט מוכן. הזר יראה רק את מה שבמעטפה — בלי שם ופרטים מזהים.
        </Text>
      </GlassCard>
      <PrimaryButton label={locking ? 'נועל...' : 'נעל מעטפה'} onPress={lock} disabled={locking} />
    </Screen>
  );
}

