  warn: { color: colors.warning, textAlign: 'right', lineHeight: 22, fontSize: 14 },
});

import { router, useLocalSearchParams } from 'expo-router';
import { useCallback, useState } from 'react';
import { Alert, StyleSheet, Text, View } from 'react-native';
import { useFocusEffect } from '@react-navigation/native';
import { api, SwapView } from '../src/api';
import { EnvelopeOrb } from '../src/components/EnvelopeOrb';
import { Screen } from '../src/components/Screen';
import { GlassCard, OutlineButton, PrimaryButton, Subtitle, Title } from '../src/components/UI';
import { useApp } from '../src/context/AppContext';
import { colors, spacing } from '../src/theme';

export default function SwapScreen() {
  const { id } = useLocalSearchParams<{ id: string }>();
  const { userId, refreshMe, setDraft } = useApp();
  const [swap, setSwap] = useState<SwapView | null>(null);

  const poll = useCallback(async () => {
    if (!userId || !id) return;
    const s = await api.getSwap(userId, id);
    setSwap(s);
  }, [userId, id]);

  useFocusEffect(
    useCallback(() => {
      poll();
      const t = setInterval(poll, 2500);
      return () => clearInterval(t);
    }, [poll]),
  );

  const finish = async () => {
    await refreshMe();
    setDraft({});
    router.replace('/');
  };

  const feedback = async (type: 'touched' | 'dishonest' | 'report') => {
    if (!userId || !id) return;
    if (type === 'report') {
      Alert.alert('דיווח', 'הדיווח נשלח. תודה על שמירה על הקהילה.', [
        { text: 'אישור', onPress: async () => {
          await api.feedback(userId, id, type);
          finish();
        }},
      ]);
      return;
    }
    await api.feedback(userId, id, type);
    finish();
  };

  if (!swap) {
    return (
      <Screen>
        <EnvelopeOrb mode="queue" />
        <Subtitle>טוען מעטפה...</Subtitle>
      </Screen>
    );
  }

  const opened = swap.phase === 'opened' && swap.peerContent;

  if (!swap.myLocked) {
    router.replace({ pathname: '/lock', params: { id: swap.id } });
    return null;
  }

  if (!opened) {
    return (
      <Screen>
        <EnvelopeOrb mode={swap.peerLocked ? 'open' : 'queue'} />
        <Title>{swap.peerLocked ? 'הזר נעל — נפתח בקרוב' : 'ממתין שהזר ינעל'}</Title>
        <Subtitle>
          {swap.peerAlias} · {swap.isBot ? 'מצב בדיקה' : 'מעטפה אנונימית'}
        </Subtitle>
        <Text style={styles.phase}>
          {swap.myLocked ? '✓ נעלת' : ''} {swap.peerLocked ? '✓ הזר נעל' : '○ ממתין לזר'}
        </Text>
      </Screen>
    );
  }

  return (
    <Screen scroll>
      <View style={styles.center}>
        <EnvelopeOrb mode="open" size={100} />
      </View>
      <Title>מעטפת מ{swap.peerAlias}</Title>
      <GlassCard>
        <Text style={styles.content}>{swap.peerContent}</Text>
      </GlassCard>
      <Subtitle>איך זה הרגיש?</Subtitle>
      <PrimaryButton label="נגע בי" onPress={() => feedback('touched')} />
      <OutlineButton label="לא כנה" onPress={() => feedback('dishonest')} />
      <OutlineButton label="דיווח" onPress={() => feedback('report')} danger />
      <OutlineButton label="סיום בלי דירוג" onPress={async () => {
        if (userId && id) await api.complete(userId, id);
        finish();
      }} />
    </Screen>
  );
}

